if (!fs.existsSync(seoDir)) fs.mkdirSync(seoDir, { recursive: true });
for (const item of pages) {
  if (!Array.isArray(item.related)) throw new Error(`${item.slug} has invalid related links`);
  fs.writeFileSync(path.join(seoDir, `${item.slug}.html`), render(item));
}

let sitemap = fs.readFileSync(sitemapPath, 'utf8');
for (const item of pages) {
  const loc = `https://workindex.co.in/seo-pages/${item.slug}.html`;
  if (!sitemap.includes(`<loc>${loc}</loc>`)) {
    sitemap = sitemap.replace('</urlset>', `  <url>\n    <loc>${loc}</loc>\n    <lastmod>${today}</lastmod>\n    <changefreq>monthly</changefreq>\n    <priority>0.8</priority>\n  </url>\n</urlset>`);
  }
}
fs.writeFileSync(sitemapPath, sitemap);
console.log(`Created ${pages.length} Batch 10 SEO pages`);
